  1→"use server";
  2→
  3→import type { Sandbox } from "e2b";
  4→import { z } from "zod";
  5→import { esc, getSandboxRuntime, runOrThrow } from "@/lib/e2b";
  6→import { orgAction } from "@/server/action-utils";
  7→
  8→// ── Create a named agent + send first message ───────────────────────────────
  9→
 10→export const createAgent = orgAction(
 11→  z.object({
 12→    sandboxId: z.string().min(1),
 13→    agentId: z.string().min(1),
 14→    description: z.string().min(1),
 15→    systemPrompt: z.string().min(1),
 16→  }),
 17→  async ({ organizationId }, input) => {
 18→    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
 19→
 20→    const exists = await agentExists(runtime, input.agentId);
 21→
 22→    if (!exists) {
 23→      const workspace = `$HOME/.openclaw/workspace-${input.agentId}`;
 24→
 25→      // 1. Create workspace + write AGENTS.md with system prompt
 26→      await runOrThrow(runtime, `mkdir -p "${workspace}"`, "create workspace");
 27→      await runOrThrow(
 28→        runtime,
 29→        `cat > "${workspace}/AGENTS.md" << 'AGENTEOF'\n${input.systemPrompt}\nAGENTEOF`,
 30→        "write AGENTS.md",
 31→      );
 32→
 33→      // 2. Register agent (ignore "already exists")
 34→      const addResult = await runtime.commands.run(
 35→        `openclaw agents add ${esc(input.agentId)} --workspace "${workspace}"`,
 36→      );
 37→      const addStderr = addResult.stderr?.trim() ?? "";
 38→      if (addResult.exitCode !== 0 && !addStderr.includes("already exists")) {
 39→        throw new Error(addStderr || `agents add failed (exit ${addResult.exitCode})`);
 40→      }
 41→
 42→      // 3. Enable delegation so main agent can spawn named agents
 43→      await runOrThrow(
 44→        runtime,
 45→        `jq '.agents.defaults.subagents.maxSpawnDepth = 2' ~/.openclaw/openclaw.json > /tmp/openclaw.json && mv /tmp/openclaw.json ~/.openclaw/openclaw.json`,
 46→        "enable delegation",
 47→      );
 48→    }
 49→
 50→    // 4. Save description for main-agent context building
 51→    await runtime.commands.run(
 52→      `cat > "$HOME/.openclaw/workspace-${input.agentId}/.description" << 'DESCEOF'\n${input.description}\nDESCEOF`,
 53→    );
 54→
 55→    // 5. Update main agent's AGENTS.md so it knows about all specialists
 56→    await updateMainAgentContext(runtime);
 57→
 58→    return { status: "created" };
 59→  },
 60→);
 61→
 62→// ── List named agents ────────────────────────────────────────────────────────
 63→
 64→export const listAgents = orgAction(
 65→  z.object({ sandboxId: z.string().min(1) }),
 66→  async ({ organizationId }, input) => {
 67→    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
 68→
 69→    // Try JSON first
 70→    const result = await runtime.commands.run(`openclaw agents list --json`);
 71→    const raw = result.stdout?.trim() ?? "";
 72→    console.log("[agents] list --json raw:", raw);
 73→
 74→    const json = extractJson(raw);
 75→    if (json) {
 76→      const agents = parseAgentsJson(json);
 77→      if (agents.length > 0) return { agents };
 78→    }
 79→
 80→    // Fallback: parse plain text output
 81→    // Format: "- <id> (default?)\n  Workspace: ..."
 82→    const plain = await runtime.commands.run(`openclaw agents list`);
 83→    const plainOut = plain.stdout ?? "";
 84→    console.log("[agents] list plain:", plainOut);
 85→
 86→    const agents: AgentInfo[] = [];
 87→    const lines = plainOut.split("\n");
 88→    for (const line of lines) {
 89→      const match = line.match(/^-\s+(\S+)/);
 90→      if (match) {
 91→        agents.push({
 92→          id: match[1],
 93→          name: match[1],
 94→          emoji: null,
 95→          workspace: null,
 96→        });
 97→      }
 98→    }
 99→
100→    return { agents };
101→  },
102→);
103→
104→// ── Delete a named agent ─────────────────────────────────────────────────────
105→
106→export const deleteAgent = orgAction(
107→  z.object({
108→    sandboxId: z.string().min(1),
109→    agentId: z.string().min(1),
110→  }),
111→  async ({ organizationId }, input) => {
112→    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
113→    await runOrThrow(
114→      runtime,
115→      `openclaw agents delete ${esc(input.agentId)} --force`,
116→      "delete agent",
117→    );
118→
119→    // Clean up workspace
120→    await runtime.commands.run(
121→      `rm -rf "$HOME/.openclaw/workspace-${input.agentId}"`,
122→    );
123→
124→    // Update main agent's AGENTS.md to remove deleted specialist
125→    await updateMainAgentContext(runtime);
126→
127→    return { ok: true as const };
128→  },
129→);
