131→// ── Helpers ──────────────────────────────────────────────────────────────────
132→
133→/**
134→ * Try to extract agent list from various JSON shapes:
135→ * - { agents: [{ id, identity, workspace }] }
136→ * - [{ id, ... }]
137→ * - { "agent-id": { ... }, ... }  (object keyed by agent ID)
138→ */
139→function parseAgentsJson(json: unknown): AgentInfo[] {
140→  if (!json || typeof json !== "object") return [];
141→
142→  // Shape 1: { agents: [...] }
143→  const withAgents = json as { agents?: unknown[] };
144→  if (Array.isArray(withAgents.agents)) {
145→    return withAgents.agents.map(agentRecordToInfo).filter((a) => a.id);
146→  }
147→
148→  // Shape 2: top-level array
149→  if (Array.isArray(json)) {
150→    return json.map(agentRecordToInfo).filter((a) => a.id);
151→  }
152→
153→  // Shape 3: object keyed by agent ID
154→  const entries = Object.entries(json as Record<string, unknown>);
155→  if (entries.length > 0 && typeof entries[0][1] === "object") {
156→    return entries.map(([key, val]) => {
157→      const rec = (val ?? {}) as Record<string, unknown>;
158→      return {
159→        id: (rec.id as string) ?? key,
160→        name: (rec.name as string | undefined) ?? key,
161→        emoji: (rec.emoji as string | undefined) ?? null,
162→        workspace: (rec.workspace as string | undefined) ?? null,
163→      };
164→    });
165→  }
166→
167→  return [];
168→}
169→
170→function agentRecordToInfo(raw: unknown): AgentInfo {
171→  const a = (raw ?? {}) as Record<string, unknown>;
172→  const identity = (a.identity ?? {}) as Record<string, unknown>;
173→  return {
174→    id: (a.id as string) ?? "",
175→    name: (identity.name as string | undefined) ?? (a.name as string | undefined) ?? (a.id as string) ?? "",
176→    emoji: (identity.emoji as string | undefined) ?? (a.emoji as string | undefined) ?? null,
177→    workspace: (a.workspace as string | undefined) ?? (a.agentDir as string | undefined) ?? null,
178→  };
179→}
180→
181→interface AgentInfo {
182→  id: string;
183→  name: string;
184→  emoji: string | null;
185→  workspace: string | null;
186→}
187→
188→async function agentExists(
189→  runtime: Sandbox,
190→  agentId: string,
191→): Promise<boolean> {
192→  try {
193→    // Try JSON first
194→    const result = await runtime.commands.run(`openclaw agents list --json`);
195→    if (result.exitCode === 0) {
196→      const json = extractJson(result.stdout?.trim() ?? "");
197→      if (json) {
198→        const parsed = json as { agents?: { id: string }[] };
199→        const agents = Array.isArray(parsed.agents) ? parsed.agents : [];
200→        if (agents.some((a) => a.id === agentId)) return true;
201→      }
202→    }
203→
204→    // Fallback: plain text — check if agent ID appears in output
205→    const plain = await runtime.commands.run(`openclaw agents list`);
206→    if (plain.exitCode === 0 && plain.stdout) {
207→      return plain.stdout.includes(agentId);
208→    }
209→
210→    return false;
211→  } catch {
212→    return false;
213→  }
214→}
