216→/**
217→ * Update the main/default agent's AGENTS.md with info about all deployed
218→ * specialist agents so it can delegate tasks via sub-agent spawning.
219→ */
220→async function updateMainAgentContext(runtime: Sandbox): Promise<void> {
221→  // 1. Collect all non-main agent IDs
222→  const result = await runtime.commands.run(`openclaw agents list`);
223→  const plainOut = result.stdout ?? "";
224→
225→  const agentIds: string[] = [];
226→  for (const line of plainOut.split("\n")) {
227→    const match = line.match(/^-\s+(\S+)/);
228→    if (match && match[1] !== "main") {
229→      agentIds.push(match[1]);
230→    }
231→  }
232→
233→  // 2. Update main agent's allowAgents list in openclaw.json
234→  const allowList = JSON.stringify(agentIds);
235→  await runtime.commands.run(
236→    `jq '(.agents.list[] | select(.id == "main")).subagents.allowAgents = ${allowList}' ~/.openclaw/openclaw.json > /tmp/openclaw.json && mv /tmp/openclaw.json ~/.openclaw/openclaw.json`,
237→  );
238→
239→  // 3. Read saved description for each specialist
240→  const specialists: { id: string; description: string }[] = [];
241→  for (const id of agentIds) {
242→    const descResult = await runtime.commands.run(
243→      `cat "$HOME/.openclaw/workspace-${id}/.description" 2>/dev/null`,
244→    );
245→    const desc = descResult.stdout?.trim() || `Specialist agent: ${id}`;
246→    specialists.push({ id, description: desc });
247→  }
248→
249→  // 4. Build the specialists block with markers so we can update it later
250→  const MARKER_START = "<!-- DEPLOYED_SPECIALISTS_START -->";
251→  const MARKER_END = "<!-- DEPLOYED_SPECIALISTS_END -->";
252→
253→  let specialistsBlock: string;
254→  if (specialists.length === 0) {
255→    specialistsBlock = `${MARKER_START}\n${MARKER_END}`;
256→  } else {
257→    const list = specialists
258→      .map((s) => `- **${s.id}**: ${s.description}`)
259→      .join("\n");
260→    specialistsBlock = `${MARKER_START}
261→## Specialist Agents
262→
263→You can delegate tasks to these deployed specialist agents:
264→
265→${list}
266→
267→When a user's request matches a specialist's expertise, delegate the task to them and summarize the results.
268→${MARKER_END}`;
269→  }
270→
271→  // 5. Get main agent's workspace from agents.defaults.workspace
272→  const wsResult = await runtime.commands.run(
273→    `cat ~/.openclaw/openclaw.json 2>/dev/null | jq -r '.agents.defaults.workspace // empty'`,
274→  );
275→  const mainWorkspace =
276→    wsResult.stdout?.trim() || "/home/user/.openclaw/workspace";
277→
278→  // 6. Read existing AGENTS.md (preserve user's custom content)
279→  const existing = await runtime.commands.run(
280→    `cat "${mainWorkspace}/AGENTS.md" 2>/dev/null`,
281→  );
282→  let content = existing.stdout ?? "";
283→
284→  // 7. Replace existing specialist section or append
285→  const startIdx = content.indexOf(MARKER_START);
286→  const endIdx = content.indexOf(MARKER_END);
287→
288→  if (startIdx !== -1 && endIdx !== -1) {
289→    content =
290→      content.slice(0, startIdx) +
291→      specialistsBlock +
292→      content.slice(endIdx + MARKER_END.length);
293→  } else {
294→    content = content.trimEnd() + "\n\n" + specialistsBlock + "\n";
295→  }
296→
297→  // 8. Write back
298→  await runtime.commands.run(`mkdir -p "${mainWorkspace}"`);
299→  await runOrThrow(
300→    runtime,
301→    `cat > "${mainWorkspace}/AGENTS.md" << 'MAINEOF'\n${content}\nMAINEOF`,
302→    "update main agent context",
303→  );
304→}
305→
306→function extractJson(raw: string): unknown | null {
307→  try {
308→    return JSON.parse(raw);
309→  } catch {
310→    // noop
311→  }
312→  const objStart = raw.indexOf("{");
313→  const arrStart = raw.indexOf("[");
314→  const start =
315→    objStart === -1
316→      ? arrStart
317→      : arrStart === -1
318→        ? objStart
319→        : Math.min(objStart, arrStart);
320→  if (start === -1) return null;
321→  const candidate = raw.slice(start);
322→  try {
323→    return JSON.parse(candidate);
324→  } catch {
325→    const lines = raw.split("\n");
326→    for (let i = lines.length - 1; i >= 0; i--) {
327→      const line = lines[i].trim();
328→      if (line.startsWith("{") || line.startsWith("[")) {
329→        try {
330→          return JSON.parse(line);
331→        } catch {
332→          continue;
333→        }
334→      }
335→    }
336→  }
337→  return null;
338→}
