158→const INVITE_EXPIRATION_MS = 7 * 24 * 60 * 60 * 1000;
159→
160→export const createInviteAction = adminAction(
161→  z.object({ email: z.string().email() }),
162→  async (ctx, { email }) => {
163→    const existingUser = await db.query.user.findFirst({
164→      where: eq(user.email, email),
165→      columns: { id: true },
166→    });
167→    if (existingUser) throw new Error("User already has an account");
168→
169→    const existingInvite = await platformInvitationRepo.findValidByEmail(email);
170→    if (existingInvite) {
171→      const inviteLink = `${clientEnv.NEXT_PUBLIC_SERVER_URL}/invite/${existingInvite.id}`;
172→      const result = await sendEmail({
173→        to: email,
174→        subject: "You're invited to RunAgents",
175→        react: PlatformInvitationEmail({ inviteLink }),
176→      });
177→      if (!result.success) {
178→        throw new Error(result.error ?? "Failed to resend email");
179→      }
180→      return { id: existingInvite.id, inviteLink };
181→    }
182→
183→    const expiresAt = new Date(Date.now() + INVITE_EXPIRATION_MS);
184→    const row = await platformInvitationRepo.create({
185→      email,
186→      invitedById: ctx.session.user.id,
187→      expiresAt,
188→    });
189→    if (!row) throw new Error("Failed to create invitation");
190→
191→    const inviteLink = `${clientEnv.NEXT_PUBLIC_SERVER_URL}/invite/${row.id}`;
192→    const result = await sendEmail({
193→      to: email,
194→      subject: "You're invited to RunAgents",
195→      react: PlatformInvitationEmail({ inviteLink }),
196→    });
197→    if (!result.success) {
198→      await platformInvitationRepo.deleteById(row.id);
199→      throw new Error(result.error ?? "Failed to send email");
200→    }
201→
202→    return { id: row.id, inviteLink };
203→  },
204→);
