"use server";

import { Sandbox } from "e2b";
import { z } from "zod";
import { env as clientEnv } from "@/env/client";
import { env } from "@/env/server";
import {
  connectSandbox,
  E2B_TEMPLATE_NAME,
  E2B_TIMEOUT_MS,
  getE2BApiKey,
  getSandboxRuntime,
  requireE2BSandboxId,
  runOrThrow,
} from "@/lib/e2b";
import { encrypt } from "@/lib/encryption";
import { orgAction, requireAdminOrOwner } from "@/server/action-utils";
import { sandboxRepo } from "@/server/db/repos/sandbox.repo";

// ── Actions ───────────────────────────────────────────────────────────────────

export const getSandboxes = orgAction(
  async ({ organizationId }) => sandboxRepo.findByOrg(organizationId),
  { skipBilling: true },
);

export const createSandbox = orgAction(
  z.object({
    name: z.string().min(1, "Name is required").max(50, "Name is too long"),
    telegramBotToken: z
      .string()
      .regex(/^\d+:[A-Za-z0-9_-]+$/, "Invalid bot token format"),
  }),
  async ({ user, organizationId }, input) => {
    // Role gate
    await requireAdminOrOwner(user.id, organizationId);

    // One-sandbox-per-org (server-side only, no DB constraint)
    const existing = await sandboxRepo.findByOrg(organizationId);
    if (existing.length > 0)
      throw new Error(
        "Your organization already has a sandbox. Delete it before deploying a new one.",
      );

    const openrouterApiKey = env.OPENROUTER_API_KEY;
    if (!openrouterApiKey)
      throw new Error("OPENROUTER_API_KEY is not configured");

    const sandboxId = crypto.randomUUID();
    const webhookSecret = crypto.randomUUID();
    const baseUrl = env.WEBHOOK_BASE_URL ?? clientEnv.NEXT_PUBLIC_SERVER_URL;
    const webhookUrl = `${baseUrl}/api/telegram/${sandboxId}`;

    const runtime = await Sandbox.betaCreate(E2B_TEMPLATE_NAME, {
      apiKey: getE2BApiKey(),
      autoPause: true,
      timeoutMs: E2B_TIMEOUT_MS,
      metadata: { organizationId, name: input.name },
    });

    try {
      await runOrThrow(
        runtime,
        `openclaw onboard \
        --non-interactive --accept-risk \
        --flow quickstart \
        --gateway-bind loopback --gateway-auth token \
        --skip-health \
        --auth-choice openrouter-api-key \
        --openrouter-api-key "${openrouterApiKey}"`,
        "Credential injection",
      );

      await runOrThrow(
        runtime,
        `jq \
          --arg botToken "${input.telegramBotToken}" \
          --arg webhookUrl "${webhookUrl}" \
          --arg webhookSecret "${webhookSecret}" \
          '
            .plugins.entries.telegram.enabled = true |
            .channels.telegram.enabled = true |
            .channels.telegram.botToken = $botToken |
            .channels.telegram.webhookUrl = $webhookUrl |
            .channels.telegram.webhookSecret = $webhookSecret
          ' ~/.openclaw/openclaw.json > /tmp/openclaw.json && mv /tmp/openclaw.json ~/.openclaw/openclaw.json`,
        "Config patch",
      );

      await runOrThrow(runtime, "openclaw gateway start", "Gateway start");

      const info = await runtime.getInfo({ requestTimeoutMs: 15_000 });

      const [telegramBotTokenEnc, webhookSecretEnc] = await Promise.all([
        encrypt(input.telegramBotToken),
        encrypt(webhookSecret),
      ]);

      return await sandboxRepo.create({
        organizationId,
        id: sandboxId,
        name: input.name,
        e2bSandboxId: runtime.sandboxId,
        e2bTemplateId: info.templateId,
        telegramBotTokenEnc,
        webhookSecretEnc,
        deploymentStatus: "running",
      });
    } catch (error) {
      await runtime.kill().catch(() => undefined);
      throw error;
    }
  },
);

export const deleteSandbox = orgAction(
  z.object({ sandboxId: z.string().min(1) }),
  async ({ user, organizationId }, input) => {
    // Role gate
    await requireAdminOrOwner(user.id, organizationId);

    const sandbox = await sandboxRepo.findById(input.sandboxId, organizationId);
    if (!sandbox) throw new Error("Sandbox not found");

    if (sandbox.e2bSandboxId) {
      const runtime = await connectSandbox(sandbox.e2bSandboxId).catch(
        () => null,
      );
      await runtime?.kill().catch(() => undefined);
    }

    await sandboxRepo.deleteById(input.sandboxId, organizationId);
  },
);

export const getSandboxRuntimeStatus = orgAction(
  z.object({ sandboxId: z.string().min(1) }),
  async ({ organizationId }, input) => {
    const sandbox = await sandboxRepo.findById(input.sandboxId, organizationId);
    if (!sandbox) throw new Error("Sandbox not found");
    const e2bSandboxId = requireE2BSandboxId(sandbox.e2bSandboxId);
    const info = await Sandbox.getInfo(e2bSandboxId, {
      apiKey: getE2BApiKey(),
    });
    return { state: info.state };
  },
);

export const wakeSandbox = orgAction(
  z.object({ sandboxId: z.string().min(1) }),
  async ({ organizationId }, input) => {
    const sandbox = await sandboxRepo.findById(input.sandboxId, organizationId);
    if (!sandbox) throw new Error("Sandbox not found");

    const e2bSandboxId = requireE2BSandboxId(sandbox.e2bSandboxId);
    await connectSandbox(e2bSandboxId);
    return { state: "running" as const };
  },
);

export const approveTelegramPairing = orgAction(
  z.object({
    sandboxId: z.string().min(1),
    pairingCode: z
      .string()
      .trim()
      .regex(/^[A-Z0-9]{6,12}$/i, "Invalid pairing code format"),
  }),
  async ({ organizationId }, input) => {
    const sandbox = await sandboxRepo.findById(input.sandboxId, organizationId);
    if (!sandbox) throw new Error("Sandbox not found");

    const e2bSandboxId = requireE2BSandboxId(sandbox.e2bSandboxId);
    const runtime = await connectSandbox(e2bSandboxId);
    await runOrThrow(
      runtime,
      `openclaw pairing approve telegram "${input.pairingCode.trim().toUpperCase()}"`,
      "Pairing approval",
    );
    return { ok: true as const };
  },
);

export const restartGateway = orgAction(
  z.object({ sandboxId: z.string().min(1) }),
  async ({ organizationId }, input) => {
    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
    await runOrThrow(
      runtime,
      `nohup openclaw gateway restart > /tmp/gateway-restart.log 2>&1 &`,
      "Gateway restart",
    );
    return { ok: true as const };
  },
);

export const getSnapshots = orgAction(
  z.object({ sandboxId: z.string().min(1) }),
  async ({ organizationId }, input) => {
    const sandbox = await sandboxRepo.findById(input.sandboxId, organizationId);
    if (!sandbox) throw new Error("Sandbox not found");
    return sandboxRepo.findSnapshotsBySandbox(input.sandboxId);
  },
);

export const createSnapshot = orgAction(
  z.object({
    sandboxId: z.string().min(1),
    name: z.string().min(1, "Name is required").max(50, "Name is too long"),
  }),
  async ({ organizationId }, input) => {
    const sandbox = await sandboxRepo.findById(input.sandboxId, organizationId);
    if (!sandbox) throw new Error("Sandbox not found");

    return sandboxRepo.createSnapshot({
      sandboxId: input.sandboxId,
      name: input.name,
    });
  },
);

