import { defaultBuildLogger, Template } from "e2b";

const TEMPLATE_NAME = "runagents-dev-20260227";
const CPU_COUNT = 2;
const MEMORY_MB = 1024 * 4;

const OPENROUTER_API_KEY =
  process.env.OPENROUTER_API_KEY || "sk-or-v1-dummy-key";
// Onboarding is baked into the image to avoid repeating the slowest step at creation time.
// Model + credential + channel config is applied per-sandbox by the create action.
const template = Template()
  .fromNodeImage("22")
  .aptInstall(["curl", "git", "wget", "jq", "dbus", "dbus-user-session"])
  // Enable linger for the default sandbox user so user@UID.service starts on boot.
  // The profile.d script sets XDG_RUNTIME_DIR dynamically for any shell session.
  .runCmd(
    "sudo mkdir -p /var/lib/systemd/linger && sudo touch /var/lib/systemd/linger/user",
  )
  .runCmd(
    "printf 'export XDG_RUNTIME_DIR=/run/user/$(id -u)\\nexport DBUS_SESSION_BUS_ADDRESS=unix:path=/run/user/$(id -u)/bus\\nexport PATH=$HOME/.npm-global/bin:$PATH\\n' | sudo tee /etc/profile.d/user-session.sh > /dev/null && sudo chmod +x /etc/profile.d/user-session.sh",
  )
  .runCmd(
    "curl -fsSL https://openclaw.ai/install.sh | bash -s -- --no-prompt --no-onboard",
  )
  .runCmd(
    `openclaw onboard \
--non-interactive --accept-risk \
--flow quickstart \
--gateway-bind loopback --gateway-auth token \
--skip-health \
--install-daemon \
--auth-choice openrouter-api-key \
--openrouter-api-key "${OPENROUTER_API_KEY}"`,
  );

async function main() {
  console.log(`Building E2B template "${TEMPLATE_NAME}"...\n`);

  const buildInfo = await Template.build(template, TEMPLATE_NAME, {
    cpuCount: CPU_COUNT,
    memoryMB: MEMORY_MB,
    onBuildLogs: defaultBuildLogger(),
  });

  console.log("Template built successfully.");
  console.log(`  Name:        ${buildInfo.name}`);
  console.log(`  Template ID: ${buildInfo.templateId}`);
  console.log(`  Build ID:    ${buildInfo.buildId}`);
}

main().catch((err) => {
  console.error("Build failed:", err);
  process.exit(1);
});

