import { Sandbox } from "e2b";
import { env } from "@/env/server";
import { sandboxRepo } from "@/server/db/repos/sandbox.repo";

export const E2B_TEMPLATE_NAME = "runagents-dev-20260227";
export const E2B_TIMEOUT_MS = 120_000;

export function getE2BApiKey(): string {
  if (!env.E2B_API_KEY) throw new Error("E2B_API_KEY is not configured");
  return env.E2B_API_KEY;
}

/** Single-quote shell escape for safe CLI argument passing */
export function esc(v: string): string {
  return `'${v.replace(/'/g, "'\\''")}'`;
}

export async function connectSandbox(e2bSandboxId: string): Promise<Sandbox> {
  return Sandbox.connect(e2bSandboxId, {
    apiKey: getE2BApiKey(),
    timeoutMs: E2B_TIMEOUT_MS,
  });
}

export async function runOrThrow(
  sandbox: Sandbox,
  cmd: string,
  label: string,
  logCmd?: string,
) {
  console.log(`[e2b] ${label} cmd:`, logCmd ?? cmd);
  try {
    const result = await sandbox.commands.run(cmd);
    const stdout = result.stdout ?? "";
    const stderr = result.stderr ?? "";
    if (result.exitCode !== 0) {
      const errMsg = [
        `[e2b] ${label} FAILED (exit ${result.exitCode})`,
        stdout && `stdout: ${stdout}`,
        stderr && `stderr: ${stderr}`,
      ]
        .filter(Boolean)
        .join("\n");
      console.error(errMsg);
      throw new Error(
        stderr.trim() ||
          stdout.trim() ||
          `${label} failed (exit ${result.exitCode})`,
      );
    }
    console.log(`[e2b] ${label} OK`);
    return result;
  } catch (err: unknown) {
    // E2B SDK throws CommandExitError with a `result` property on non-zero exit
    const cmdErr = err as {
      result?: { stdout?: string; stderr?: string; exitCode?: number };
      message?: string;
    };
    if (cmdErr.result) {
      const stdout = cmdErr.result.stdout ?? "";
      const stderr = cmdErr.result.stderr ?? "";
      const exitCode = cmdErr.result.exitCode ?? 1;
      const errMsg = [
        `[e2b] ${label} FAILED (exit ${exitCode})`,
        stdout && `stdout: ${stdout}`,
        stderr && `stderr: ${stderr}`,
      ]
        .filter(Boolean)
        .join("\n");
      console.error(errMsg);
      throw new Error(
        stderr.trim() || stdout.trim() || `${label} failed (exit ${exitCode})`,
      );
    }
    // Not a CommandExitError — log and rethrow
    console.error(`[e2b] ${label} exception:`, cmdErr.message ?? err);
    throw err;
  }
}

export function requireE2BSandboxId(
  e2bSandboxId: string | null | undefined,
): string {
  if (!e2bSandboxId?.trim()) throw new Error("Sandbox is not provisioned yet");
  return e2bSandboxId.trim();
}

export async function getSandboxRuntime(
  sandboxId: string,
  // userId: string,
  organizationId: string,
): Promise<Sandbox> {
  // const sandbox = await sandboxRepo.findById(sandboxId, userId);
  const sandbox = await sandboxRepo.findById(sandboxId, organizationId);
  if (!sandbox) throw new Error("Sandbox not found");
  const e2bSandboxId = requireE2BSandboxId(sandbox.e2bSandboxId);
  return connectSandbox(e2bSandboxId);
}

